INSERT INTO public.training_items
  (category_id, title, title_en, title_es, body, body_en, body_es, sort_order, is_published)
SELECT cat.id, 'Teknikval, branscher & pris', 'Tech choice, industries & price', 'Elección técnica, sectores y precio',
       $j${"type": "doc", "content": [{"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Hemsidor"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Statisk i Astro"}, {"type": "text", "text": " — presenterar mest, ändras sällan. Snabbt, billigt att drifta, säkert, toppbetyg i SEO."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Branscher"}, {"type": "text", "text": ": hantverk & bygg (takläggare, el, VVS, måleri, snickeri), tjänsteföretag (redovisning, jurist, konsult, arkitekt), lokalt (restaurang, frisör, tandläkare, klinik, gym, hotell)."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Typiskt pris"}, {"type": "text", "text": ": landningssida från 9 000 kr; företagshemsida (upp till 7 sidor) 18 000 kr."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Dynamisk i React/JavaScript"}, {"type": "text", "text": " — interaktivitet, inloggning, realtidsdata, kalkylator eller portal."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Branscher/behov"}, {"type": "text", "text": ": bokning (klinik, salong, event), kundportaler (försäkring, energi, B2B), pris-/offertkalkylator (solceller, kök/fönster, bilhandlare), medlems- och communitysajter."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Typiskt pris"}, {"type": "text", "text": ": från 49 000 kr (gränsar till webbapp – exakt pris efter behovsanalys)."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "E-handel (egen plattform)"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Start"}, {"type": "text", "text": ": liten eller nischad butik, hantverkare/restaurang med få produkter. Från 19 000 kr + 1 490 kr/mån."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Plus (populärast)"}, {"type": "text", "text": ": växande varumärken – mode, inredning, skönhet, sport. Från 35 000 kr + 2 490 kr/mån."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Pro (enterprise)"}, {"type": "text", "text": ": grossist/partihandel, B2B med kundpriser, möbel- och byggvaror, stort sortiment, flera marknader, ERP-integration (Fortnox/Visma). Från 59 000 kr + 4 900 kr/mån."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Produktbolag (bygger en digital produkt)"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "MVP"}, {"type": "text", "text": " – startup som validerar en idé (marknadsplats, SaaS-koncept, fintech-prototyp). Från 29 000 kr."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Webbapp (React)"}, {"type": "text", "text": " – SaaS, internt verktyg, bokningsplattform, dashboard, B2B-portal. Från 49 000 kr."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Mobilapp (React Native)"}, {"type": "text", "text": " – konsumenttjänst (lojalitet, leverans, träning, community) eller fältarbete. Från 79 000 kr."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Säljtips"}, {"type": "text", "text": ": börja i kundens behov, inte i tekniken. Orden \"logga in\", \"boka\", \"räkna ut\", \"lagersaldo\" och \"kundportal\" avgör om det blir Astro, React eller app – och därmed prisnivån. Priserna är utgångslägen; större omfång blir offert."}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Websites"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Static in Astro"}, {"type": "text", "text": " — mostly presents, rarely changes. Fast, cheap to run, secure, top SEO scores."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Industries"}, {"type": "text", "text": ": trades & construction (roofers, electricians, plumbing, painting, carpentry), service firms (accounting, legal, consulting, architecture), local businesses (restaurant, hair salon, dentist, clinic, gym, hotel)."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Typical price"}, {"type": "text", "text": ": landing page from SEK 9,000; business website (up to 7 pages) SEK 18,000."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Dynamic in React/JavaScript"}, {"type": "text", "text": " — interactivity, login, real-time data, a calculator or a portal."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Industries/needs"}, {"type": "text", "text": ": booking (clinic, salon, events), customer portals (insurance, energy, B2B), price/quote calculators (solar, kitchens/windows, car dealers), membership and community sites."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Typical price"}, {"type": "text", "text": ": from SEK 49,000 (borders on a web app – exact price after a needs analysis)."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "E-commerce (own platform)"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Start"}, {"type": "text", "text": ": a small or niche store, a tradesperson/restaurant with a few products. From SEK 19,000 + SEK 1,490/mo."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Plus (most popular)"}, {"type": "text", "text": ": growing brands – fashion, interior, beauty, sports. From SEK 35,000 + SEK 2,490/mo."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Pro (enterprise)"}, {"type": "text", "text": ": wholesale/distribution, B2B with customer pricing, furniture and building materials, large catalogues, multiple markets, ERP integration (Fortnox/Visma). From SEK 59,000 + SEK 4,900/mo."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Product companies (building a digital product)"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "MVP"}, {"type": "text", "text": " – a startup validating an idea (marketplace, SaaS concept, fintech prototype). From SEK 29,000."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Web app (React)"}, {"type": "text", "text": " – SaaS, internal tool, booking platform, dashboard, B2B portal. From SEK 49,000."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Mobile app (React Native)"}, {"type": "text", "text": " – a consumer service (loyalty, delivery, fitness, community) or field work. From SEK 79,000."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Sales tip"}, {"type": "text", "text": ": start from the customer's need, not the tech. The words \"log in\", \"book\", \"calculate\", \"stock\" and \"customer portal\" decide whether it's Astro, React or an app – and thus the price level. Prices are starting points; larger scope is quoted."}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Webs"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Estático en Astro"}, {"type": "text", "text": " — sobre todo presenta, cambia poco. Rápido, barato de mantener, seguro y con SEO excelente."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Sectores"}, {"type": "text", "text": ": oficios y construcción (tejados, electricistas, fontanería, pintura, carpintería), empresas de servicios (contabilidad, abogacía, consultoría, arquitectura), negocios locales (restaurante, peluquería, dentista, clínica, gimnasio, hotel)."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Precio típico"}, {"type": "text", "text": ": página de aterrizaje desde 9 000 SEK; web corporativa (hasta 7 páginas) 18 000 SEK."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Dinámico en React/JavaScript"}, {"type": "text", "text": " — interactividad, inicio de sesión, datos en tiempo real, una calculadora o un portal."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Sectores/necesidades"}, {"type": "text", "text": ": reservas (clínica, salón, eventos), portales de cliente (seguros, energía, B2B), calculadoras de precio/presupuesto (solar, cocinas/ventanas, concesionarios), sitios de socios y comunidad."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Precio típico"}, {"type": "text", "text": ": desde 49 000 SEK (roza una aplicación web; precio exacto tras un análisis de necesidades)."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "E-commerce (plataforma propia)"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Start"}, {"type": "text", "text": ": una tienda pequeña o de nicho, un artesano/restaurante con pocos productos. Desde 19 000 SEK + 1 490 SEK/mes."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Plus (el más popular)"}, {"type": "text", "text": ": marcas en crecimiento: moda, interiorismo, belleza, deporte. Desde 35 000 SEK + 2 490 SEK/mes."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Pro (enterprise)"}, {"type": "text", "text": ": mayoristas/distribución, B2B con precios por cliente, muebles y materiales de construcción, catálogos grandes, varios mercados, integración ERP (Fortnox/Visma). Desde 59 000 SEK + 4 900 SEK/mes."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Empresas de producto (que construyen un producto digital)"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "MVP"}, {"type": "text", "text": " – una startup que valida una idea (marketplace, concepto SaaS, prototipo fintech). Desde 29 000 SEK."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Aplicación web (React)"}, {"type": "text", "text": " – SaaS, herramienta interna, plataforma de reservas, dashboard, portal B2B. Desde 49 000 SEK."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Aplicación móvil (React Native)"}, {"type": "text", "text": " – un servicio de consumo (fidelización, entrega, fitness, comunidad) o trabajo de campo. Desde 79 000 SEK."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Consejo de venta"}, {"type": "text", "text": ": parte de la necesidad del cliente, no de la tecnología. Las palabras \"iniciar sesión\", \"reservar\", \"calcular\", \"stock\" y \"portal de cliente\" deciden si es Astro, React o una app, y con ello el nivel de precio. Los precios son puntos de partida; un alcance mayor se presupuesta."}]}]}$j$::jsonb, 0, true
FROM public.training_categories cat
WHERE cat.slug = 'produktkunskap'
  AND NOT EXISTS (
    SELECT 1 FROM public.training_items ti
    WHERE ti.category_id = cat.id AND ti.title = 'Teknikval, branscher & pris'
  );
